VALUES
  ('judicial-cf446b4c-moex-00334', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲乙丙共有A地，其應有部分各為1/3。甲未經乙丙同意，而擅自在A地上架設太陽能板。試問： 乙丙不得對甲主張下列何種權利？', '["因債務不履行之損害賠償請求權", "共有物返還請求權", "不當得利請求權", "侵權行為損害賠償請求權 20420 20520"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00335', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲因赴外地工作，遂將其所有之A車交付予乙，由乙為其保管。雙方並約定乙每週短暫發動引擎 兩次，以免A車因長時間停放而受損。下列敘述，何者正確？', '["若甲乙就A車之返還，定有返還期限時，則甲不得隨時請求返還", "若甲乙就A車之返還，未定有返還期限時，則乙得隨時返還", "若乙未經甲之同意，即逕取A車載友人丙出遊。途中因另一駕駛丁未注意車前狀況而撞上等紅 燈之乙，致A車車尾凹陷，則乙就A車所生之損害，對甲不負損害賠償責任", "若乙未受有報酬，仍應以善良管理人之注意保管A車"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00336', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲發現乙有珍貴花卉種籽，暗自取走後，將種籽栽種於甲之母丙的農地上。半年後花朵盛開，該 花朵現為何人所有？', '["甲", "乙", "丙", "乙丙共有"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00337', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲向乙借款，並將所有之A屋設定最高限額抵押權予乙。下列敘述，何者錯誤？', '["乙將對甲之債權讓與給丙，該最高限額抵押權並不隨同移轉給丙", "乙對甲之債權如歸於消滅，該最高限額抵押權亦隨之消滅", "該最高限額抵押權不因乙死亡而消滅", "乙實行抵押權之費用不計入抵押權擔保債權之最高限額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00338', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於民法區分所有建築物規定之敘述，何者錯誤？', '["區分所有建築物，乃數人區分一建築物而各專有其一部，就專有部分有單獨所有權，並就該建 築物及其附屬物之共同部分共有之建築物", "專有部分與其所屬之共有部分及其基地之權利，得分離而為移轉或設定負擔", "共有部分除法律另有規定外，得經規約之約定供區分所有建築物之特定所有人使用", "專有部分得經其所有人之同意，依規約之約定供區分所有建築物之所有人共同使用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00339', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於普通地上權地租之敘述，何者錯誤？', '["地上權定有期限，而有支付地租之約定者，地上權人得支付未到期之2年分地租後，拋棄地上權", "地上權未定有期限，而有支付地租之約定者，地上權人得支付未到期之1年分地租後，拋棄地 上權", "地上權設定後，因土地價值之昇降，依原定地租給付顯失公平者，當事人得請求法院增減之", "土地所有權讓與時，已預付之地租，非經登記，不得對抗第三人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00340', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲患有思覺失調症（原稱精神分裂症），時癒時發，經甲母乙之協助隱瞞，甲於某年4月1日成功與 丙結婚。丙結婚次月1 日始發現上開情節，丙於同年12月1日訴請撤銷甲丙之結婚，是否有理？', '["無理，丙發見詐欺後起訴，已逾6個月", "有理，乙為第三人，不得對表意人為詐欺", "有理，丙發見詐欺後起訴，未逾1年", "有理，甲非明知第三人為詐欺，但與有過失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00341', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲、乙共同繼承父親現金新臺幣（下同）1000萬元，而甲生前曾向父親消費借貸500萬元，還沒 有償還，經計算甲僅得繼承父親遺產250萬元。其法律關係為何？', '["特留分扣減權", "特種贈與", "普通贈與", "債務之扣還"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00342', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-3d2b73b6', 'sub-judicial-cf446b4c-06', NULL, 'single_choice', '下列何者為憲法增修條文所明定之基本國策？', '["扶助弱勢政黨", "扶助人民興辦之中小型經濟事業", "保障身心障礙者之收入", "保障大陸地區人民政治參與"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00343', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-3d2b73b6', 'sub-judicial-cf446b4c-06', NULL, 'single_choice', '依憲法增修條文規定，教育、科學、文化之經費，應如何編列？', '["國民教育經費應優先編列", "基本教育經費應優先編列", "學行俱優無力升學之學生獎學金應優先編列", "邊遠及貧瘠地區之教育文化經費應優先編列"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
